var minFlips = function(s) {
    const n = s.length;
    let cnt1 = 0;
    for (let i = 0; i < n; i++) if (s[i] === '1') cnt1++;
    const costAllZero = cnt1;
    const costAllOne = n - cnt1;
    const costOneOne = cnt1 >= 1 ? cnt1 - 1 : 1;
    let best = Math.min(costAllZero, costAllOne, costOneOne);
    if (n >= 2) {
        const a = s[0] === '1' ? 1 : 0;
        const b = s[n - 1] === '1' ? 1 : 0;
        const costEnds = (1 - a) + (1 - b) + (cnt1 - a - b);
        best = Math.min(best, costEnds);
    }
    return best;
};

