class Solution:
    def minFlips(self, s):
        n = len(s)

        def has_sub(t, pat):
            it = iter(t)
            return all(c in it for c in pat)

        def coherent(t):
            return not has_sub(t, '011') and not has_sub(t, '110')

        if n > 18:
            # fall back to the closed-form shapes for longer strings so the
            # oracle still terminates; only used as a differential check on
            # small literal inputs in practice.
            cnt1 = s.count('1')
            best = min(cnt1, n - cnt1, (cnt1 - 1) if cnt1 >= 1 else 1)
            if n >= 2:
                a = 1 if s[0] == '1' else 0
                b = 1 if s[-1] == '1' else 0
                best = min(best, (1 - a) + (1 - b) + (cnt1 - a - b))
            return best
        for d in range(n + 1):
            from itertools import combinations
            for positions in combinations(range(n), d):
                t = list(s)
                for p in positions:
                    t[p] = '1' if t[p] == '0' else '0'
                if coherent(''.join(t)):
                    return d
        return n
